// ---- CONFIG (update if infra changes) ----
const PIPELINE_SECRET   = 'YOUR_PIPELINE_SECRET';     // must match N8N_PIPELINE_SECRET in training scripts
const LAUNCHER_SECRET   = 'YOUR_LAUNCHER_SECRET'; // must match LAUNCHER_SECRET on CT 1018
const LAUNCHER_URL      = 'http://10.1.4.232:8765/launch';
const TELEGRAM_CHAT_ID  = 'REPLACE_WITH_YOUR_CHAT_ID'; // your Telegram chat ID

// ---- STAGE DEFINITIONS ----
const STAGES = {
  M2: {
    pass_criteria: { ep7_success_rate: 0.80 },
    pass: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' },
    fail: { stage: 'HUMAN_REVIEW', note: 'M2 failed — manual intervention required' }
  },
  M3: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' },
    fail: { stage: 'M3b', config: 'training/configs/m3b_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' }
  },
  M3b: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'HUMAN_REVIEW', note: 'M3b passed ✅ — implement train_m4_transitions.py and confirm before launching M4' },
    fail: { stage: 'M3c', config: 'training/configs/m3c_all_eps_tqc.yaml', module: 'training.train_m3_all_eps' }
  },
  M3c: {
    pass_criteria: { overall_success_rate: 0.75 },
    pass: { stage: 'HUMAN_REVIEW', note: 'M3c passed ✅ — ready for M4 implementation' },
    fail: { stage: 'HUMAN_REVIEW', note: 'M3c failed ❌ — hyperparameter tuning needed' }
  }
};

// ---- VALIDATE SECRET ----
const incomingSecret = $input.first().headers['x-pipeline-secret'] || '';
if (incomingSecret !== PIPELINE_SECRET) {
  throw new Error('Invalid pipeline secret — request rejected');
}

// ---- PARSE INCOMING DATA ----
const data = $input.first().json;
const milestone = data.milestone || 'UNKNOWN';
const metrics   = data.metrics   || {};
const runName   = data.run_name  || 'unknown';
const runId     = data.run_id    || 'unknown';

// ---- EVALUATE CRITERIA ----
const stageDef = STAGES[milestone];
let passed  = false;
let next    = { stage: 'HUMAN_REVIEW', note: 'Stage not defined in pipeline_stages' };
let reasons = [];

if (stageDef) {
  const criteria = stageDef.pass_criteria;
  const checks = Object.entries(criteria).map(([k, threshold]) => {
    const actual = typeof metrics[k] === 'number' ? metrics[k] : 0;
    const ok = actual >= threshold;
    reasons.push(`${k}: ${(actual*100).toFixed(0)}% (need ${(threshold*100).toFixed(0)}%) ${ok ? '✅' : '❌'}`);
    return ok;
  });
  passed = checks.every(Boolean);
  next   = passed ? stageDef.pass : stageDef.fail;
}

// ---- BUILD LAUNCH PAYLOAD (only if next stage is a real training run) ----
const canLaunch = next.stage && next.stage !== 'HUMAN_REVIEW' && next.module && next.config;
const launchPayload = canLaunch ? {
  secret: LAUNCHER_SECRET,
  module: next.module,
  config: next.config
} : null;

// ---- FORMAT TELEGRAM MESSAGE ----
const statusIcon = passed ? '✅' : '⚠️';
const epTable = [0,1,2,3,4,5,6,7].map(i => {
  const sr  = metrics[`ep${i}_success_rate`];
  const bar = typeof sr === 'number' ? (sr >= 0.8 ? '🟢' : sr >= 0.5 ? '🟡' : '🔴') : '⬜';
  return `EP${i}: ${bar} ${typeof sr === 'number' ? (sr*100).toFixed(0)+'%' : 'n/a'}`;
}).join('  ');

const lines = [
  `*Triple Pendulum — ${milestone} ${statusIcon}*`,
  `Run: \`${runName}\``,
  '',
  '*Per-EP success rates:*',
  epTable,
  '',
  '*Criteria:*',
  ...reasons,
  '',
  canLaunch
    ? `*Next: launching ${next.stage}*\n\`${next.config}\``
    : `*Next: ${next.stage}*\n${next.note || ''}`,
];
const message = lines.join('\n');

return [{ json: {
  milestone, runName, runId, passed, next, launchPayload, message,
  telegramChatId: TELEGRAM_CHAT_ID,
  launcherUrl: LAUNCHER_URL,
  metrics,
} }];
